const steps = [
  {
    number: '01',
    title: 'Remplissez le formulaire',
    description: 'En 2 minutes,apez vos informations et votre profil de chauffeur.'
  },
  {
    number: '02',
    title: 'Analyse de votre profil',
    description: 'Nos experts analysent votre situation pour trouver les meilleures offres.'
  },
  {
    number: '03',
    title: 'Comparez les offres',
    description: 'Recevez plusieurs devis personnalisés et comparez les garanties.'
  },
  {
    number: '04',
    title: 'Souscrivez et assuré',
    description: 'Choisissez votre offre et recevez votre attestation immédiatement.'
  }
];

export default function Steps() {
  return (
    <section className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Comment <span className="text-blue-800">ça marche</span> ?
          </h2>
          <p className="mt-4 text-gray-600 text-lg max-w-2xl mx-auto">
            4 étapes simples pour obtenir votre assurance taxi en quelques minutes
          </p>
        </div>

        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {steps.map((step, index) => (
            <div key={index} className="relative">
              <div className="text-center">
                <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-100 rounded-2xl mb-4">
                  <span className="text-2xl font-bold text-blue-800">{step.number}</span>
                </div>
                <h3 className="text-lg font-bold text-gray-900 mb-2">{step.title}</h3>
                <p className="text-gray-600 text-sm">{step.description}</p>
              </div>
              {index < steps.length - 1 && (
                <div className="hidden lg:block absolute top-8 left-1/2 w-full h-0.5 bg-gray-200 -translate-y-1/2"></div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
